  stimulus_type = NULL,
  options = '[{"id":"A","text":"The cat sat on the mat, and the dog watched him.","is_correct":true,"explanation":"Choice A is the only correctly punctuated sentence. It uses a comma to separate the two independent clauses joined by the coordinating conjunction \"and.\"  The other choices are incorrect because they either fail to use a comma before the conjunction or they use incorrect punctuation. Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The cat sat on the mat and the dog watched him.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The cat sat on the mat; and the dog watched him.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The cat sat on the mat, and the dog watched him;","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
